long double InitConst::geoHarms[3][25][25];     // неизменямый массив, используется в модели
long double InitConst::geoHarmsPert[3][25][25]; // используется в алгоритме Каннингема и приливах, нестандартное расположение гармоник
long double InitConst::q[25][25], InitConst::qx[25][25], InitConst::qz[25][25];


//заполнение массивов для geopot
void InitConst::geoConst(int NM, int MN){

    //заполняются поля класса InitConst::CV,Q,QX,QZ, gNorm
    //метод позволяет заполнять массивы для любого числа имеющихся гармоник
    long double CNST[NM][NM+1];
    long double SNST[NM][NM+1];
    long double CN, C2N, CNM1, C2NP1, C2NM1, C2NP3, C2NM3;
    long double CM, CNPM, CNMM, CN2MM2, DM;

    //обнуление CV
    for (int i=0; i<NM+2;i++){
        for (int j=0; j<NM+2; j++){
            for (int k=0; k<2; k++){
                CV[k][i][j]=0.0;
            }
        }
    }

    //типо считывание первый и вторых коэ-тов в матрицы
    int countGarm = 0;
    for (int N=0; N<=NM; N++){
        for (int M=0; M<=N; M++){
            CV[0][M][N+1] = geoHarmsOriginal[countGarm][2];
            CV[1][M][N+1] = geoHarmsOriginal[countGarm][3];
            countGarm += 1;
        }
    }

    //обнуление массива CNST, SNST
    for (int i=0; i<NM; i++){
        for (int j=0; j<NM+1; j++ ){
            CNST[i][j] = 0.0;
            SNST[i][j] = 0.0;
        }
    }
    //заполнение CNST SNST
    for (int N=0; N<NM; N++){
        for (int M=0; M<=N+1; M++){
            CNST[N][M] = CV[0][M][N+2];
            SNST[N][M] = CV[1][M][N+2];
        }
    }

    int IN = NM;
    for (int i=0; i<NM; i++){
        for (int j=0; j<NM; j++){
            Q[i][j] = 0.0;
            QX[i][j] = 0.0;
            QZ[i][j] = 0.0;
        }
    }

    //заполнение Q, QX, QZ
    int N,M,MM1;
    for (int I=0; I<IN; I++){
        N = I;
        CN = static_cast<long double>(N);
        C2N = CN + CN;
        CNM1 = CN - 1.0;
        C2NP1 = C2N + 1.0;
        C2NM1 = C2N - 1.0;
        C2NP3 = C2N + 3.0;
        C2NM3 = C2N - 3.0;
        for (int J=0; J<=I; J++){
            M = J;
            MM1 = M - 1;
            CM = static_cast<long double>(M);
            CNPM = CN + CM;
            CNMM = CN - CM;
            CN2MM2 = CNPM*CNMM;
            DM = 1.0;
            if (M==0) DM = 2.0;
            QX[I][J] = sqrt(C2NP1*(CNPM+2.0)*(CNPM+1.0)/(DM*C2NP3));

            if (MM1 >= 0) {
                if (MM1 == 0) DM = 2.0;
                QX[M-1][I] = sqrt(DM*C2NP1*(CNMM+2.0)*(CNMM+1.0)/C2NP3);

            }

            if (N == M) {
                if (N != 0) Q[I][J] = sqrt(DM*C2NP1/C2N);
            } else {
                Q[I][J] = sqrt(C2NP1*C2NM1/CN2MM2);
                Q[J][I] = sqrt(C2NP1*(CNM1+CM)*(CNM1-CM)/(CN2MM2*C2NM3));
            }
            QZ[I][J] = sqrt(C2NP1*(CNPM+1.0)*(CNMM+1.0)/C2NP3);
        }
    }
}

// Общая инициализация, которая вызывается в самом начале
void InitConst::generalInit() {
    int sizeRows = sizeof(geoHarmsOriginal) / sizeof(geoHarmsOriginal[0]);

    // Заполнение массивов с гармониками
    for (int k = 0; k < sizeRows; k++) {
        int order = geoHarmsOriginal[k][0];
        int degree = geoHarmsOriginal[k][1];

        // Заполнение в стандартном порядке (массив не меняется в численной модели)
        geoHarms[1][order][degree] = geoHarmsOriginal[k][2];
        geoHarms[2][order][degree] = geoHarmsOriginal[k][3];

        // Заполнение в порядке, который используется в алгоритме Каннингема
        geoHarmsPert[1][degree + 1][order + 2] = geoHarms[1][order][degree];
        geoHarmsPert[2][degree + 1][order + 2] = geoHarms[2][order][degree];
    }

    // Вычисление коэффиентов для алгоритма Каннингема
//    gNorm = gravParam[EARTH] / pow(raduisEarth, 2);
    int nMax = geoHarmsOriginal[sizeRows - 1][0];

    for (int i = 1; i <= nMax; i++) {
        int n = i - 1;
        double cn = static_cast<double>(n);
        double c2n = cn + cn;
        double cnm1 = cn - 1.0;
        double c2np1 = c2n + 1.0;
        double c2nm1 = c2n - 1.0;
        double c2np3 = c2n + 3.0;
        double c2nm3 = c2n - 3.0;

        for (int j = 1; j <= i; j++) {
            int m = j - 1;
            int mm1 = m - 1;
            double cm = static_cast<double>(m);
            double cnpm = cn + cm;
            double cnmm = cn - cm;
            double cn2mm2 = cnpm * cnmm;
            double dm = 1.0;

            if (m == 0) dm = 2.0;
            qx[i][j] = sqrt(c2np1 * (cnpm + 2.0) * (cnpm + 1.0) / (dm * c2np3));

            if (mm1 >= 0) {
                if (mm1 == 0) dm = 2.0;
                qx[m][i] = sqrt(dm * c2np1 * (cnmm + 2.0) * (cnmm + 1.0) / c2np3);
            }

            if (n == m) {
                if (n != 0) q[i][j] = sqrt(dm * c2np1 / c2n);
            } else {
                q[i][j] = sqrt(c2np1 * c2nm1 / cn2mm2);
                q[j][i] = sqrt(c2np1 * (cnm1 + cm) * (cnm1 - cm) / (cn2mm2 * c2nm3));
            }

            qz[i][j] = sqrt(c2np1 * (cnpm + 1.0) * (cnmm + 1.0) / c2np3);
        }
    }
}
